import{_ as e,o as l,c as a,a7 as i}from"./chunks/framework.C5fSpjcB.js";const f=JSON.parse('{"title":"デイリー攻略","description":"","frontmatter":{},"headers":[],"relativePath":"ja/guides/dailies.md","filePath":"ja/guides/dailies.md","lastUpdated":1775394001000}'),d={name:"ja/guides/dailies.md"};function r(n,t,s,h,o,c){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="デイリー攻略" tabindex="-1">デイリー攻略 <a class="header-anchor" href="#デイリー攻略" aria-label="Permalink to &quot;デイリー攻略&quot;">​</a></h1><p>毎日効率的にプレイするためのデイリールーティンガイドです。</p><h2 id="デイリーチェックリスト" tabindex="-1">デイリーチェックリスト <a class="header-anchor" href="#デイリーチェックリスト" aria-label="Permalink to &quot;デイリーチェックリスト&quot;">​</a></h2><h3 id="必須-毎日必ず実行" tabindex="-1">必須（毎日必ず実行） <a class="header-anchor" href="#必須-毎日必ず実行" aria-label="Permalink to &quot;必須（毎日必ず実行）&quot;">​</a></h3><ul><li>[ ] デイリーミッションの完了</li><li>[ ] スタミナの消費（資源ステージ or 調査行動）</li><li>[ ] 派遣の回収・再設定</li><li>[ ] ショップの無料枠確認</li><li>[ ] フレンドへの挨拶（フレンドポイント）</li></ul><h3 id="推奨-時間がある時に" tabindex="-1">推奨（時間がある時に） <a class="header-anchor" href="#推奨-時間がある時に" aria-label="Permalink to &quot;推奨（時間がある時に）&quot;">​</a></h3><ul><li>[ ] 調査行動（Investigation）のデイリー分消化</li><li>[ ] 相位対局（PvP）のデイリー対戦</li><li>[ ] イベントステージの消化</li><li>[ ] 意識潜游の進行</li></ul><h3 id="週間タスク" tabindex="-1">週間タスク <a class="header-anchor" href="#週間タスク" aria-label="Permalink to &quot;週間タスク&quot;">​</a></h3><ul><li>[ ] ウィークリーミッションの完了</li><li>[ ] 資源ステージの曜日素材周回</li><li>[ ] チャレンジステージの週間報酬</li></ul><h2 id="スタミナ効率" tabindex="-1">スタミナ効率 <a class="header-anchor" href="#スタミナ効率" aria-label="Permalink to &quot;スタミナ効率&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">用途</th><th style="text-align:center;">優先度</th><th style="text-align:left;">備考</th></tr></thead><tbody><tr><td style="text-align:left;">イベントステージ</td><td style="text-align:center;">最高</td><td style="text-align:left;">期間限定のため最優先</td></tr><tr><td style="text-align:left;">資源ステージ（不足素材）</td><td style="text-align:center;">高</td><td style="text-align:left;">育成に必要な素材を優先周回</td></tr><tr><td style="text-align:left;">チャレンジステージ</td><td style="text-align:center;">高</td><td style="text-align:left;">密契・刻印の厳選</td></tr><tr><td style="text-align:left;">メインステージ</td><td style="text-align:center;">中</td><td style="text-align:left;">未クリア分がある場合</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>スタミナは溢れさせないことが最も重要です。就寝前にスタミナを消費し、長時間派遣をセットしましょう。</p></div><h2 id="効率的なプレイ時間" tabindex="-1">効率的なプレイ時間 <a class="header-anchor" href="#効率的なプレイ時間" aria-label="Permalink to &quot;効率的なプレイ時間&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">時間帯</th><th style="text-align:left;">やること</th><th style="text-align:center;">所要時間</th></tr></thead><tbody><tr><td style="text-align:left;">朝</td><td style="text-align:left;">派遣回収、デイリーミッション確認</td><td style="text-align:center;">5分</td></tr><tr><td style="text-align:left;">昼</td><td style="text-align:left;">短時間派遣回収、スタミナ消費</td><td style="text-align:center;">10分</td></tr><tr><td style="text-align:left;">夜</td><td style="text-align:left;">メインプレイ（調査行動・PvP等）</td><td style="text-align:center;">30〜60分</td></tr><tr><td style="text-align:left;">就寝前</td><td style="text-align:left;">スタミナ消費、長時間派遣設定</td><td style="text-align:center;">5分</td></tr></tbody></table><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./beginner.html">初心者ガイド</a></li><li><a href="./../stages/resource.html">資源ステージ</a></li><li><a href="./../modes/dispatch.html">派遣</a></li><li><a href="./../modes/investigation.html">調査行動</a></li></ul>',16)])])}const g=e(d,[["render",r]]);export{f as __pageData,g as default};
